module.exports = function(RED) {
    function InsertCodeNode(config) {
        RED.nodes.createNode(this, config);
        var node = this;
        
        // Récupération des valeurs configurées
        this.emplacement = config.emplacement || "Variables";
        this.code = config.code || "";

        node.on('close', function() {
            // Nettoyage si nécessaire lors de la suppression/redéploiement
        });
    }
    RED.nodes.registerType("insert-code", InsertCodeNode);
}